import{_ as a,o,c as e,a2 as r}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"逆向思维 Contrarian Thinking","description":"别人贪婪时我恐惧，别人恐惧时我贪婪","frontmatter":{"title":"逆向思维 Contrarian Thinking","description":"别人贪婪时我恐惧，别人恐惧时我贪婪"},"headers":[],"relativePath":"02_concepts/contrarian.md","filePath":"02_concepts/contrarian.md"}'),l={name:"02_concepts/contrarian.md"};function n(i,t,d,h,u,q){return o(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="逆向思维-contrarian-thinking" tabindex="-1">逆向思维 Contrarian Thinking <a class="header-anchor" href="#逆向思维-contrarian-thinking" aria-label="Permalink to &quot;逆向思维 Contrarian Thinking&quot;">​</a></h1><hr><h2 id="核心出处" tabindex="-1">核心出处 <a class="header-anchor" href="#核心出处" aria-label="Permalink to &quot;核心出处&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年份</th><th style="text-align:left;">重点内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>1987年</strong></td><td style="text-align:left;">&quot;别人贪婪时我恐惧&quot;经典阐述</td></tr><tr><td style="text-align:left;"><strong>1994年</strong></td><td style="text-align:left;">棒球理论：不挥棒不会三振出局</td></tr><tr><td style="text-align:left;"><strong>2008年</strong></td><td style="text-align:left;">金融危机中的逆向买入</td></tr><tr><td style="text-align:left;"><strong>2009年</strong></td><td style="text-align:left;">&quot;也许十年最悲观的时候&quot;</td></tr><tr><td style="text-align:left;"><strong>2020年</strong></td><td style="text-align:left;">百年一遇疫情中的机会</td></tr></tbody></table><hr><h2 id="核心原则" tabindex="-1">核心原则 <a class="header-anchor" href="#核心原则" aria-label="Permalink to &quot;核心原则&quot;">​</a></h2><p>巴菲特的逆向思维可能是他最广为人知的投资哲学陈述。这句话被无数人引用，却很少有人真正做到：</p><blockquote><p>&quot;别人贪婪时我恐惧，别人恐惧时我贪婪。&quot;<br> ——沃伦·巴菲特</p></blockquote><p>这不仅是投资策略，更是一种深刻的人性洞察。大多数人在市场中的行为模式是社会性的——他们跟随多数人的判断，因为那样感觉&quot;安全&quot;。但投资市场恰恰是少数人赚钱的地方，这意味着<strong>随大流几乎注定平庸</strong>。</p><h2 id="逆向思维的本质" tabindex="-1">逆向思维的本质 <a class="header-anchor" href="#逆向思维的本质" aria-label="Permalink to &quot;逆向思维的本质&quot;">​</a></h2><h3 id="不是简单的-反着来" tabindex="-1">不是简单的&quot;反着来&quot; <a class="header-anchor" href="#不是简单的-反着来" aria-label="Permalink to &quot;不是简单的&quot;反着来&quot;&quot;">​</a></h3><p>逆向思维不等于故意唱反调。巴菲特的逆向建立在扎实的研究和独立判断之上。</p><blockquote><p>&quot;你的行为必须与众不同，但如果你错误地逆向，那将是最糟糕的事情。&quot;<br> ——沃伦·巴菲特，2016年致股东信</p></blockquote><p>逆向思维的核心是<strong>独立思考</strong>：不被群体的情绪裹挟，用自己的分析来判断价值，而不是用价格来代替思考。</p><h3 id="等待极端而不是寻找平庸" tabindex="-1">等待极端而不是寻找平庸 <a class="header-anchor" href="#等待极端而不是寻找平庸" aria-label="Permalink to &quot;等待极端而不是寻找平庸&quot;">​</a></h3><p>巴菲特不是在市场稍微悲观时买入，而是在极端恐慌或贪婪的时刻出手。</p><blockquote><p>&quot;关键不是在别人贪婪时恐惧，或者在别人恐惧时贪婪。关键是在极度贪婪和极度恐惧的时刻采取行动。普通人不会在市场下跌 10% 时感到极度恐惧——他们只会在市场下跌 40% 或 50% 时才真正感到恐惧。&quot;<br> ——沃伦·巴菲特，2018年伯克希尔年度股东大会</p></blockquote><h2 id="逆向思维在实践中的应用" tabindex="-1">逆向思维在实践中的应用 <a class="header-anchor" href="#逆向思维在实践中的应用" aria-label="Permalink to &quot;逆向思维在实践中的应用&quot;">​</a></h2><h3 id="恐惧时刻的案例" tabindex="-1">恐惧时刻的案例 <a class="header-anchor" href="#恐惧时刻的案例" aria-label="Permalink to &quot;恐惧时刻的案例&quot;">​</a></h3><p>2008年金融危机期间，市场一片恐慌，巴菲特却在众人恐惧中大举出手：</p><blockquote><p>&quot;恐惧是传染病。2008年秋天，这种疾病从纽约的银行和经纪人传播到各地。人们被恐惧感染——包括一些本应理智的投资者。我在1987年10月19日（黑色星期一）没有行动，那是个错误。但我在这次危机中行动了。&quot;<br> ——沃伦·巴菲特，2009年致股东信</p></blockquote><p>他在那一年写下了那句著名的话：</p><blockquote><p>&quot;Buy when there&#39;s blood in the streets, even if the blood is your own.&quot;（当街头流血时买入，即使那血是你自己的。）<br> ——沃伦·巴菲特</p></blockquote><h3 id="贪婪时刻的案例" tabindex="-1">贪婪时刻的案例 <a class="header-anchor" href="#贪婪时刻的案例" aria-label="Permalink to &quot;贪婪时刻的案例&quot;">​</a></h3><p>反过来，巴菲特在市场极度亢奋时选择退场。1999年科技股泡沫顶峰时，他在太阳谷发表了著名的演讲，公开质疑当时的估值逻辑。</p><blockquote><p>&quot;一个投资者如果在他的投资组合中以当前价格持有美国股市指数，他正在经历一段困难的时期——不是一年，而是十年。但这个投资者正在为自己创造一个不舒服的未来。&quot;<br> ——沃伦·巴菲特，1999年太阳谷演讲</p></blockquote><p>后来的市场崩盘证明了他是对的。</p><h2 id="逆向思维的心理学基础" tabindex="-1">逆向思维的心理学基础 <a class="header-anchor" href="#逆向思维的心理学基础" aria-label="Permalink to &quot;逆向思维的心理学基础&quot;">​</a></h2><h3 id="损失厌恶与群体压力" tabindex="-1">损失厌恶与群体压力 <a class="header-anchor" href="#损失厌恶与群体压力" aria-label="Permalink to &quot;损失厌恶与群体压力&quot;">​</a></h3><p>人类天然厌恶损失，这种情绪在群体中会被放大。当市场下跌时，身边的人都在卖出，你的内心会承受巨大的社会压力。巴菲特对此有清醒的认识：</p><blockquote><p>&quot;投资只需要做好一件事——在别人做出错误判断时保持正确的判断。但这并不容易，因为你所处的环境——媒体、其他投资者——都会不断告诉你为什么你应该随大流。&quot;<br> ——沃伦·巴菲特</p></blockquote><h3 id="流动性幻觉" tabindex="-1">流动性幻觉 <a class="header-anchor" href="#流动性幻觉" aria-label="Permalink to &quot;流动性幻觉&quot;">​</a></h3><blockquote><p>&quot;流动性是你的敌人。如果你有一个你真正喜欢的十年投资前景，用流动性来让你动摇是一个错误。&quot;<br> ——沃伦·巴菲特</p></blockquote><p>当所有人都急着抛售时，市场提供了流动性，但这种流动性往往是以极端折扣价为代价的。逆向投资者需要放弃这种&quot;随时可以逃跑&quot;的安全感。</p><h2 id="查理·芒格的补充" tabindex="-1">查理·芒格的补充 <a class="header-anchor" href="#查理·芒格的补充" aria-label="Permalink to &quot;查理·芒格的补充&quot;">​</a></h2><p>巴菲特的搭档查理·芒格对此有更深刻的哲学表达：</p><blockquote><p>&quot;反过来看，总是反过来看。&quot;（Invert, always invert.）</p></blockquote><p>芒格认为，很多问题从反面思考会更容易找到答案。你想成功？那就先研究所有失败的原因。你想避免风险？那就先研究历史上最惨烈的投资灾难。</p><blockquote><p>&quot;我一直在寻找什么是错误的，然后努力避免它。大多数人不是这样做的。&quot;<br> ——查理·芒格</p></blockquote><h2 id="逆向思维的常见误区" tabindex="-1">逆向思维的常见误区 <a class="header-anchor" href="#逆向思维的常见误区" aria-label="Permalink to &quot;逆向思维的常见误区&quot;">​</a></h2><table tabindex="0"><thead><tr><th>误区</th><th>正确做法</th></tr></thead><tbody><tr><td>简单地与大众相反</td><td>基于独立研究判断，而不是为了逆向而逆向</td></tr><tr><td>越跌越买而不考虑基本面</td><td>逆向的前提是标的本身没有问题，只是被市场错杀</td></tr><tr><td>在任何恐慌时刻都买入</td><td>只在极端情况下出手，而且要确保子弹充足</td></tr><tr><td>忽视基本面变化</td><td>区分&quot;恐慌导致的下跌&quot;和&quot;基本面恶化导致的下跌&quot;</td></tr></tbody></table><h2 id="逆向需要勇气-更需要准备" tabindex="-1">逆向需要勇气，更需要准备 <a class="header-anchor" href="#逆向需要勇气-更需要准备" aria-label="Permalink to &quot;逆向需要勇气，更需要准备&quot;">​</a></h2><p>巴菲特的逆向不是冲动，而是在机会来临之前就做好了充分准备。</p><blockquote><p>&quot;每隔十年左右，乌云就会笼罩经济的天空，一阵流星雨也会随之而来。天空会瞬间再次晴朗，但陨石坠落时，地面上的人甚至不会抬头看一眼。在那种时候，我们应该低下头，利用这个机会——前提是我们已经准备好了。&quot;<br> ——沃伦·巴菲特，2016年致股东信</p></blockquote><p>他在2008年能够果断出手，是因为伯克希尔账上有充足的现金。这提醒我们：<strong>逆向的机会永远存在，但只有准备好的人才能抓住它。</strong></p><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>逆向思维不是投资的万能公式，而是一种需要长期训练的思维方式。它要求你：</p><ol><li><strong>独立思考</strong>——不被群体情绪裹挟</li><li><strong>深入研究</strong>——在逆向之前确信自己的判断</li><li><strong>耐心等待</strong>——等待极端而不是平庸</li><li><strong>做好准备</strong>——在机会来临时有足够的资本和勇气行动</li></ol><blockquote><p>&quot;投资的成功与你有多聪明关系不大。真正重要的是你是否有一种既能让你在别人恐慌时保持理性，又能在机会出现时果断行动的性情。&quot;<br> ——沃伦·巴菲特，2008年致股东信</p></blockquote>',49)])])}const b=a(l,[["render",n]]);export{c as __pageData,b as default};
